import React, { useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Page } from '../components/Layout';
import { getAllCompanies, getAllVariants } from '../services/authService';
import { CARS } from '../mockCars';

export default function HomePage() {
  const navigate = useNavigate();
  const [cars, setCars] = useState(CARS);
  const [companies, setCompanies] = useState([]);
  const [selectedCompany, setSelectedCompany] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadData = async () => {
      try {
        const [variantsData, companiesData] = await Promise.all([
          getAllVariants(),
          getAllCompanies()
        ]);

        if (Array.isArray(variantsData) && variantsData.length > 0) {
          setCars(
            variantsData.map((item) => ({
              id: item.id,
              name: item.name,
              company: item.company,
              modelNumber: item.modelNumber,
              fuelType: item.fuelType,
              seats: item.seatCapacity,
              year: item.year,
              isAC: item.isAc,
              rentPerDay: item.rentPerDay,
              image: item.image || CARS[0].image,
              description: item.description || 'Drive in comfort with this premium rental option.',
              features: [
                item.isAc ? 'AC' : 'Non-AC',
                item.fuelType || 'Fuel Efficient',
                `${item.seatCapacity || 4} Seats`,
                item.modelNumber || 'Modern Features'
              ],
              badge: 'Available'
            }))
          );
        }

        if (Array.isArray(companiesData)) {
          setCompanies(companiesData);
        }
      } catch (error) {
        // Fallback to local mock data when backend has no variant seed data yet.
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, []);

  const filteredCars = useMemo(() => {
    if (!selectedCompany) {
      return cars;
    }
    return cars.filter((car) => car.company === selectedCompany);
  }, [cars, selectedCompany]);

  return (
    <Page
      title="Drive Your Dream Car Today"
      subtitle="Browse available cars, log in with your role, and send booking requests for admin approval."
    >
      <section className="searchPanel card">
        <div>
          <h3>Search Cars</h3>
          <p>Choose a company to quickly filter available variants.</p>
        </div>
        <div className="searchControls">
          <select value={selectedCompany} onChange={(event) => setSelectedCompany(event.target.value)}>
            <option value="">All Companies</option>
            {companies.map((company) => (
              <option key={company.id} value={company.name}>
                {company.name}
              </option>
            ))}
          </select>
          <button className="button" onClick={() => setSelectedCompany('')}>Reset</button>
        </div>
      </section>

      {loading && <div className="alert success">Loading available cars...</div>}

      <section className="grid cards3">
        {filteredCars.map((car) => (
          <article className="card carCard" key={car.id}>
            <img src={car.image} alt={car.name} className="carImage" />
            <div className="tag">{car.badge}</div>
            <h3>{car.name}</h3>
            <p>{car.company} • {car.fuelType} • {car.seats} seats • {car.modelNumber}</p>
            <div className="cardRow">
              <strong>₹{car.rentPerDay.toLocaleString()}/day</strong>
              <button className="button" onClick={() => navigate(`/car/detail/${car.id}`)}>
                Book Now
              </button>
            </div>
          </article>
        ))}
      </section>
    </Page>
  );
}
